    78вҶ’  lastUpdated: Date;
    79вҶ’  statusDistribution: {
    80вҶ’    fit: number;
    81вҶ’    inMaintenance: number;
    82вҶ’    outOfService: number;
    83вҶ’    restricted: number;
    84вҶ’  };
    85вҶ’  pmDueSummary: {
    86вҶ’    thisWeek: Record<PMLevel, number>;
    87вҶ’    thisMonth: Record<PMLevel, number>;
    88вҶ’    overdue: Record<PMLevel, number>;
    89вҶ’  };
    90вҶ’  mileageStats: {
    91вҶ’    totalFleetMileage: number;
    92вҶ’    averageMileage: number;
    93вҶ’    minMileage: number;
    94вҶ’    maxMileage: number;
    95вҶ’  };
    96вҶ’}
    97вҶ’
    98вҶ’/**
    99вҶ’ * Train status for grid display
