   297вҶ’
   298вҶ’// ============================================================================
   299вҶ’// Dashboard Layout Types
   300вҶ’// ============================================================================
   301вҶ’
   302вҶ’/**
   303вҶ’ * User role for dashboard customisation
   304вҶ’ */
   305вҶ’export type DashboardRole =
   306вҶ’  | 'fleet_manager'
   307вҶ’  | 'maintenance_planner'
   308вҶ’  | 'operations_manager'
   309вҶ’  | 'executive'
   310вҶ’  | 'technician_supervisor';
   311вҶ’
   312вҶ’/**
   313вҶ’ * Dashboard view mode
   314вҶ’ */
   315вҶ’export type DashboardViewMode = 'executive' | 'operational' | 'focus';
   316вҶ’
   317вҶ’/**
   318вҶ’ * Widget identifier
   319вҶ’ */
   320вҶ’export type WidgetId =
   321вҶ’  | 'kpi_cards'
   322вҶ’  | 'fleet_status'
   323вҶ’  | 'alerts'
   324вҶ’  | 'pm_timeline'
   325вҶ’  | 'resource_chart'
   326вҶ’  | 'run_assignments'
   327вҶ’  | 'cost_compliance'
   328вҶ’  | 'mileage_variance'
   329вҶ’  | 'quick_actions';
   330вҶ’
   331вҶ’/**
   332вҶ’ * Widget configuration
   333вҶ’ */
   334вҶ’export interface WidgetConfig {
   335вҶ’  id: WidgetId;
   336вҶ’  title: string;
   337вҶ’  enabled: boolean;
   338вҶ’  position: { row: number; col: number };
   339вҶ’  size: { width: number; height: number }; // Grid units
   340вҶ’  collapsed: boolean;
   341вҶ’  refreshInterval: number; // milliseconds, 0 = manual only
   342вҶ’}
   343вҶ’
   344вҶ’/**
   345вҶ’ * Dashboard layout configuration
   346вҶ’ */
   347вҶ’export interface DashboardLayout {
   348вҶ’  id: string;
   349вҶ’  name: string;
   350вҶ’  role: DashboardRole;
   351вҶ’  viewMode: DashboardViewMode;
   352вҶ’  widgets: WidgetConfig[];
   353вҶ’  isDefault: boolean;
   354вҶ’  createdAt: Date;
   355вҶ’  updatedAt: Date;
   356вҶ’}
   357вҶ’
   358вҶ’/**
   359вҶ’ * Dashboard state
   360вҶ’ */
   361вҶ’export interface DashboardState {
   362вҶ’  currentLayout: DashboardLayout;
   363вҶ’  selectedDate: Date;
   364вҶ’  selectedFleet?: FleetType;
   365вҶ’  isRefreshing: boolean;
   366вҶ’  lastRefreshed: Date;
   367вҶ’  alerts: DashboardAlert[];
   368вҶ’  kpiData: KPICardData[];
   369вҶ’  fleetStatus: FleetStatusSummary[];
   370вҶ’  pmTimeline: PMTimelineMarker[];
   371вҶ’  runAssignments: DailyAssignmentSummary;
   372вҶ’}
   373вҶ’
   374вҶ’// ============================================================================
   375вҶ’// Colour System
   376вҶ’// ============================================================================
   377вҶ’
   378вҶ’/**
   379вҶ’ * Dashboard colour palette
   380вҶ’ */
   381вҶ’export const DASHBOARD_COLORS = {
   382вҶ’  // Backgrounds
   383вҶ’  background: { light: '#F9FAFB', dark: '#111827' },
   384вҶ’  cardBackground: { light: '#FFFFFF', dark: '#1F2937' },
   385вҶ’
   386вҶ’  // Text
   387вҶ’  textPrimary: { light: '#111827', dark: '#F9FAFB' },
   388вҶ’  textSecondary: { light: '#6B7280', dark: '#9CA3AF' },
   389вҶ’
   390вҶ’  // Borders
   391вҶ’  border: { light: '#E5E7EB', dark: '#374151' },
   392вҶ’
   393вҶ’  // Status colours
   394вҶ’  success: { bg: '#F0FDF4', text: '#166534', border: '#22C55E' },
   395вҶ’  warning: { bg: '#FFFBEB', text: '#854D0E', border: '#F59E0B' },
   396вҶ’  error: { bg: '#FEF2F2', text: '#991B1B', border: '#EF4444' },
   397вҶ’  info: { bg: '#EFF6FF', text: '#1E40AF', border: '#3B82F6' },
   398вҶ’
   399вҶ’  // Fleet colours
   400вҶ’  kinkiSharyo: { primary: '#0891B2', light: '#CFFAFE', dark: '#164E63' },
   401вҶ’  alstom: { primary: '#7C3AED', light: '#EDE9FE', dark: '#4C1D95' },
