   405вҶ’};
   406вҶ’
   407вҶ’// ============================================================================
   408вҶ’// Responsive Breakpoints
   409вҶ’// ============================================================================
   410вҶ’
   411вҶ’/**
   412вҶ’ * Breakpoint configuration
   413вҶ’ */
   414вҶ’export const BREAKPOINTS = {
   415вҶ’  mobile: 768,
   416вҶ’  tablet: 1024,
   417вҶ’  laptop: 1440,
   418вҶ’  desktop: 1920,
   419вҶ’} as const;
   420вҶ’
   421вҶ’/**
   422вҶ’ * Grid configuration per breakpoint
   423вҶ’ */
   424вҶ’export const GRID_CONFIG = {
   425вҶ’  mobile: { columns: 4, gutter: 16, margin: 16 },
   426вҶ’  tablet: { columns: 8, gutter: 20, margin: 24 },
   427вҶ’  laptop: { columns: 12, gutter: 24, margin: 32 },
   428вҶ’  desktop: { columns: 12, gutter: 24, margin: 48 },
   429вҶ’} as const;
   430вҶ’
   431вҶ’// ============================================================================
   432вҶ’// Helper Functions
   433вҶ’// ============================================================================
   434вҶ’
   435вҶ’/**
   436вҶ’ * Determine KPI state based on value and thresholds
   437вҶ’ */
   438вҶ’export function getKPIState(
   439вҶ’  value: number,
   440вҶ’  warningThreshold: number,
   441вҶ’  criticalThreshold: number,
   442вҶ’  invertThresholds = false
   443вҶ’): KPIState {
   444вҶ’  if (invertThresholds) {
   445вҶ’    // Lower is worse (e.g., availability)
   446вҶ’    if (value < criticalThreshold) return 'critical';
   447вҶ’    if (value < warningThreshold) return 'warning';
   448вҶ’    return 'good';
   449вҶ’  } else {
   450вҶ’    // Higher is worse (e.g., cost variance)
   451вҶ’    if (Math.abs(value) > criticalThreshold) return 'critical';
   452вҶ’    if (Math.abs(value) > warningThreshold) return 'warning';
   453вҶ’    return 'good';
   454вҶ’  }
   455вҶ’}
   456вҶ’
   457вҶ’/**
   458вҶ’ * Format KPI value for display
   459вҶ’ */
   460вҶ’export function formatKPIValue(value: number, unit: KPICardData['unit']): string {
   461вҶ’  switch (unit) {
   462вҶ’    case '%':
   463вҶ’      return `${value.toFixed(1)}%`;
   464вҶ’    case 'km':
   465вҶ’      if (value >= 1000000) return `${(value / 1000000).toFixed(1)}M km`;
   466вҶ’      if (value >= 1000) return `${(value / 1000).toFixed(1)}K km`;
   467вҶ’      return `${value.toFixed(0)} km`;
   468вҶ’    case 'trains':
   469вҶ’      return `${value}`;
   470вҶ’    case 'hours':
   471вҶ’      return `${value.toFixed(0)}h`;
   472вҶ’    case 'currency':
   473вҶ’      if (Math.abs(value) >= 1000000) return `$${(value / 1000000).toFixed(1)}M`;
   474вҶ’      if (Math.abs(value) >= 1000) return `$${(value / 1000).toFixed(1)}K`;
   475вҶ’      return `$${value.toFixed(0)}`;
   476вҶ’    default:
   477вҶ’      return String(value);
   478вҶ’  }
   479вҶ’}
   480вҶ’
   481вҶ’/**
   482вҶ’ * Get trend direction from value change
   483вҶ’ */
   484вҶ’export function getTrendDirection(current: number, previous: number): TrendDirection {
   485вҶ’  const diff = current - previous;
   486вҶ’  if (Math.abs(diff) < 0.001) return 'stable';
   487вҶ’  return diff > 0 ? 'up' : 'down';
   488вҶ’}
   489вҶ’
   490вҶ’/**
   491вҶ’ * Calculate fleet status distribution percentages
   492вҶ’ */
   493вҶ’export function calculateStatusPercentages(summary: FleetStatusSummary): {
   494вҶ’  fit: number;
   495вҶ’  inMaintenance: number;
   496вҶ’  outOfService: number;
   497вҶ’  restricted: number;
   498вҶ’} {
   499вҶ’  const total = summary.totalTrains;
   500вҶ’  if (total === 0) {
   501вҶ’    return { fit: 0, inMaintenance: 0, outOfService: 0, restricted: 0 };
   502вҶ’  }
   503вҶ’
   504вҶ’  return {
   505вҶ’    fit: (summary.statusDistribution.fit / total) * 100,
   506вҶ’    inMaintenance: (summary.statusDistribution.inMaintenance / total) * 100,
   507вҶ’    outOfService: (summary.statusDistribution.outOfService / total) * 100,
   508вҶ’    restricted: (summary.statusDistribution.restricted / total) * 100,
   509вҶ’  };
   510вҶ’}
   511вҶ’
   512вҶ’/**
   513вҶ’ * Get default widget configuration for a role
   514вҶ’ */
   515вҶ’export function getDefaultWidgetsForRole(role: DashboardRole): WidgetConfig[] {
   516вҶ’  const baseWidgets: WidgetConfig[] = [
   517вҶ’    { id: 'kpi_cards', title: 'Key Metrics', enabled: true, position: { row: 0, col: 0 }, size: { width: 12, height: 2 }, collapsed: false, refreshInterval: 60000 },
   518вҶ’    { id: 'alerts', title: 'Alerts & Warnings', enabled: true, position: { row: 2, col: 6 }, size: { width: 6, height: 4 }, collapsed: false, refreshInterval: 30000 },
   519вҶ’  ];
   520вҶ’
   521вҶ’  switch (role) {
   522вҶ’    case 'fleet_manager':
   523вҶ’      return [
   524вҶ’        ...baseWidgets,
   525вҶ’        { id: 'fleet_status', title: 'Fleet Status', enabled: true, position: { row: 2, col: 0 }, size: { width: 6, height: 4 }, collapsed: false, refreshInterval: 60000 },
   526вҶ’        { id: 'pm_timeline', title: 'PM Schedule', enabled: true, position: { row: 6, col: 0 }, size: { width: 12, height: 3 }, collapsed: false, refreshInterval: 300000 },
   527вҶ’        { id: 'cost_compliance', title: 'Cost Compliance', enabled: true, position: { row: 9, col: 0 }, size: { width: 6, height: 4 }, collapsed: false, refreshInterval: 3600000 },
   528вҶ’      ];
   529вҶ’
   530вҶ’    case 'maintenance_planner':
   531вҶ’      return [
   532вҶ’        ...baseWidgets,
   533вҶ’        { id: 'pm_timeline', title: 'PM Schedule', enabled: true, position: { row: 2, col: 0 }, size: { width: 6, height: 4 }, collapsed: false, refreshInterval: 300000 },
   534вҶ’        { id: 'resource_chart', title: 'Resource Utilisation', enabled: true, position: { row: 6, col: 0 }, size: { width: 12, height: 4 }, collapsed: false, refreshInterval: 300000 },
   535вҶ’        { id: 'mileage_variance', title: 'Mileage Variance', enabled: true, position: { row: 10, col: 0 }, size: { width: 6, height: 3 }, collapsed: false, refreshInterval: 300000 },
   536вҶ’      ];
   537вҶ’
   538вҶ’    case 'operations_manager':
