/**
 * Dashboard Types - Centralised Dashboard Components
 *
 * TypeScript types for the mileage management dashboard UI.
 * Based on UX specification MILEAGE-UX-003.
 */

import type { FleetType, PMLevel, FitnessStatus, TrainStatus } from './train';

// ============================================================================
// KPI Card Types
// ============================================================================

/**
 * KPI card state based on thresholds
 */
export type KPIState = 'normal' | 'warning' | 'critical' | 'good';

/**
 * Trend direction for KPI changes
 */
export type TrendDirection = 'up' | 'down' | 'stable';

/**
 * KPI metric identifier
 */
export type KPIMetricId =
  | 'fleet_availability'
  | 'pm_compliance'
  | 'resource_utilisation'
  | 'cost_variance'
  | 'mileage_balance'
  | 'trains_in_service';

/**
 * KPI card data
 */
export interface KPICardData {
  id: KPIMetricId;
  label: string;
  value: number;
  unit: '%' | 'km' | 'trains' | 'hours' | 'currency';
  displayValue: string;
  trend: {
    direction: TrendDirection;
    value: number;
    period: string; // e.g., "vs last month"
  };
  state: KPIState;
  sparklineData?: number[];
  contextText?: string; // e.g., "121/128 trains available"
  warningThreshold: number;
  criticalThreshold: number;
  invertThresholds?: boolean; // true if lower is worse (e.g., availability)
}

/**
 * KPI thresholds configuration
 */
export interface KPIThresholds {
  metricId: KPIMetricId;
  warningMin?: number;
  warningMax?: number;
  criticalMin?: number;
  criticalMax?: number;
}

// ============================================================================
// Fleet Status Types
// ============================================================================

/**
 * Fleet status summary for dashboard panel
 */
export interface FleetStatusSummary {
  fleetType: FleetType;
  totalTrains: number;
  lastUpdated: Date;
  statusDistribution: {
    fit: number;
    inMaintenance: number;
    outOfService: number;
    restricted: number;
  };
  pmDueSummary: {
    thisWeek: Record<PMLevel, number>;
    thisMonth: Record<PMLevel, number>;
    overdue: Record<PMLevel, number>;
  };
  mileageStats: {
    totalFleetMileage: number;
    averageMileage: number;
    minMileage: number;
    maxMileage: number;
  };
}

/**
 * Train status for grid display
 */
export interface TrainStatusRow {
  trainId: string;
  name: string;
  fleetType: FleetType;
  currentMileage: number;
  lifetimeMileage: number;
  fitnessStatus: FitnessStatus;
  status: TrainStatus;
  nextPM: {
    level: PMLevel;
    dueDate: Date;
    kmRemaining: number;
    percentToThreshold: number;
  };
  todayAssignment?: {
    routeId: string;
    estimatedKm: number;
    status: 'assigned' | 'pending' | 'unassigned';
  };
  lastServiceDate: Date;
  baseDepot: string;
}

// ============================================================================
// Alert Types
// ============================================================================

/**
 * Alert severity level
 */
export type AlertSeverity = 'critical' | 'warning' | 'info' | 'success';

/**
 * Alert category
 */
export type AlertCategory =
  | 'pm_approaching'
  | 'mileage_overrun'
  | 'mileage_underrun'
  | 'resource_gap'
  | 'compliance_issue'
  | 'system_notification'
  | 'run_assignment';

/**
 * Dashboard alert
 */
export interface DashboardAlert {
  id: string;
  severity: AlertSeverity;
  category: AlertCategory;
  title: string;
  message: string;
  timestamp: Date;
  isRead: boolean;
  isDismissed: boolean;
  relatedEntities?: {
    trainIds?: string[];
    maintenanceIds?: string[];
    routeIds?: string[];
  };
  actions: AlertAction[];
  expiresAt?: Date;
}

/**
 * Alert action button
 */
export interface AlertAction {
  id: string;
  label: string;
  type: 'primary' | 'secondary' | 'dismiss';
  href?: string;
  onClick?: string; // Action identifier for event handling
}

/**
 * Alert styling configuration
 */
export const ALERT_STYLES: Record<AlertSeverity, {
  bgColor: string;
  textColor: string;
  borderColor: string;
  icon: string;
}> = {
  critical: {
    bgColor: '#FEF2F2',
    textColor: '#991B1B',
    borderColor: '#DC2626',
    icon: 'error',
  },
  warning: {
    bgColor: '#FFFBEB',
    textColor: '#854D0E',
    borderColor: '#F59E0B',
    icon: 'warning',
  },
  info: {
    bgColor: '#EFF6FF',
    textColor: '#1E40AF',
    borderColor: '#3B82F6',
    icon: 'info',
  },
  success: {
    bgColor: '#F0FDF4',
    textColor: '#166534',
    borderColor: '#22C55E',
    icon: 'check_circle',
  },
};

// ============================================================================
// PM Timeline Types
// ============================================================================

/**
 * PM schedule timeline marker
 */
export interface PMTimelineMarker {
  id: string;
  trainId: string;
  trainName: string;
  fleetType: FleetType;
  level: PMLevel;
  scheduledDate: Date;
  status: 'completed' | 'in_progress' | 'scheduled' | 'overdue';
  durationHours: number;
  depot: string;
}

/**
 * Timeline view configuration
 */
export interface TimelineConfig {
  startDate: Date;
  endDate: Date;
  zoomLevel: '7d' | '14d' | '30d' | '90d' | '1y';
  showCompletedPMs: boolean;
  filterByFleet?: FleetType;
  filterByPMLevel?: PMLevel[];
}

/**
 * PM level colour configuration
 */
export const PM_LEVEL_COLORS: Record<PMLevel, {
  primary: string;
  light: string;
  dark: string;
}> = {
  PM1: { primary: '#3B82F6', light: '#DBEAFE', dark: '#1E40AF' },
  PM2: { primary: '#6366F1', light: '#E0E7FF', dark: '#3730A3' },
  PM3: { primary: '#8B5CF6', light: '#EDE9FE', dark: '#5B21B6' },
  OVERHAUL: { primary: '#F97316', light: '#FFEDD5', dark: '#C2410C' },
};

// ============================================================================
// Run Assignment Types
// ============================================================================

/**
 * Run assignment status
 */
export type AssignmentStatus = 'assigned' | 'pending' | 'unassigned' | 'conflict';

/**
 * Run assignment row for table display
 */
export interface RunAssignmentRow {
  routeId: string;
  routeName: string;
  trainId?: string;
  trainName?: string;
  fleetType?: FleetType;
  fitnessStatus?: FitnessStatus;
  estimatedKm: number;
  actualKm?: number;
  status: AssignmentStatus;
  assignedAt?: Date;
  assignedBy?: string;
  notes?: string;
  conflicts?: string[];
}

/**
 * Daily run assignment summary
 */
export interface DailyAssignmentSummary {
  date: Date;
  totalRoutes: number;
  assignedCount: number;
  pendingCount: number;
  unassignedCount: number;
  conflictCount: number;
  assignments: RunAssignmentRow[];
}

// ============================================================================
// Dashboard Layout Types
// ============================================================================

/**
 * User role for dashboard customisation
 */
export type DashboardRole =
  | 'fleet_manager'
  | 'maintenance_planner'
  | 'operations_manager'
  | 'executive'
  | 'technician_supervisor';

/**
 * Dashboard view mode
 */
export type DashboardViewMode = 'executive' | 'operational' | 'focus';

/**
 * Widget identifier
 */
export type WidgetId =
  | 'kpi_cards'
  | 'fleet_status'
  | 'alerts'
  | 'pm_timeline'
  | 'resource_chart'
  | 'run_assignments'
  | 'cost_compliance'
  | 'mileage_variance'
  | 'quick_actions';

/**
 * Widget configuration
 */
export interface WidgetConfig {
  id: WidgetId;
  title: string;
  enabled: boolean;
  position: { row: number; col: number };
  size: { width: number; height: number }; // Grid units
  collapsed: boolean;
  refreshInterval: number; // milliseconds, 0 = manual only
}

/**
 * Dashboard layout configuration
 */
export interface DashboardLayout {
  id: string;
  name: string;
  role: DashboardRole;
  viewMode: DashboardViewMode;
  widgets: WidgetConfig[];
  isDefault: boolean;
  createdAt: Date;
  updatedAt: Date;
}

/**
 * Dashboard state
 */
export interface DashboardState {
  currentLayout: DashboardLayout;
  selectedDate: Date;
  selectedFleet?: FleetType;
  isRefreshing: boolean;
  lastRefreshed: Date;
  alerts: DashboardAlert[];
  kpiData: KPICardData[];
  fleetStatus: FleetStatusSummary[];
  pmTimeline: PMTimelineMarker[];
  runAssignments: DailyAssignmentSummary;
}

// ============================================================================
// Colour System
// ============================================================================

/**
 * Dashboard colour palette
 */
export const DASHBOARD_COLORS = {
  // Backgrounds
  background: { light: '#F9FAFB', dark: '#111827' },
  cardBackground: { light: '#FFFFFF', dark: '#1F2937' },

  // Text
  textPrimary: { light: '#111827', dark: '#F9FAFB' },
  textSecondary: { light: '#6B7280', dark: '#9CA3AF' },

  // Borders
  border: { light: '#E5E7EB', dark: '#374151' },

  // Status colours
  success: { bg: '#F0FDF4', text: '#166534', border: '#22C55E' },
  warning: { bg: '#FFFBEB', text: '#854D0E', border: '#F59E0B' },
  error: { bg: '#FEF2F2', text: '#991B1B', border: '#EF4444' },
  info: { bg: '#EFF6FF', text: '#1E40AF', border: '#3B82F6' },

  // Fleet colours
  kinkiSharyo: { primary: '#0891B2', light: '#CFFAFE', dark: '#164E63' },
  alstom: { primary: '#7C3AED', light: '#EDE9FE', dark: '#4C1D95' },

  // Actions
  primaryAction: { light: '#3B82F6', dark: '#60A5FA' },
};

// ============================================================================
// Responsive Breakpoints
// ============================================================================

/**
 * Breakpoint configuration
 */
export const BREAKPOINTS = {
  mobile: 768,
  tablet: 1024,
  laptop: 1440,
  desktop: 1920,
} as const;

/**
 * Grid configuration per breakpoint
 */
export const GRID_CONFIG = {
  mobile: { columns: 4, gutter: 16, margin: 16 },
  tablet: { columns: 8, gutter: 20, margin: 24 },
  laptop: { columns: 12, gutter: 24, margin: 32 },
  desktop: { columns: 12, gutter: 24, margin: 48 },
} as const;

// ============================================================================
// Helper Functions
// ============================================================================

/**
 * Determine KPI state based on value and thresholds
 */
export function getKPIState(
  value: number,
  warningThreshold: number,
  criticalThreshold: number,
  invertThresholds = false
): KPIState {
  if (invertThresholds) {
    // Lower is worse (e.g., availability)
    if (value < criticalThreshold) return 'critical';
    if (value < warningThreshold) return 'warning';
    return 'good';
  } else {
    // Higher is worse (e.g., cost variance)
    if (Math.abs(value) > criticalThreshold) return 'critical';
    if (Math.abs(value) > warningThreshold) return 'warning';
    return 'good';
  }
}

/**
 * Format KPI value for display
 */
export function formatKPIValue(value: number, unit: KPICardData['unit']): string {
  switch (unit) {
    case '%':
      return `${value.toFixed(1)}%`;
    case 'km':
      if (value >= 1000000) return `${(value / 1000000).toFixed(1)}M km`;
      if (value >= 1000) return `${(value / 1000).toFixed(1)}K km`;
      return `${value.toFixed(0)} km`;
    case 'trains':
      return `${value}`;
    case 'hours':
      return `${value.toFixed(0)}h`;
    case 'currency':
      if (Math.abs(value) >= 1000000) return `$${(value / 1000000).toFixed(1)}M`;
      if (Math.abs(value) >= 1000) return `$${(value / 1000).toFixed(1)}K`;
      return `$${value.toFixed(0)}`;
    default:
      return String(value);
  }
}

/**
 * Get trend direction from value change
 */
export function getTrendDirection(current: number, previous: number): TrendDirection {
  const diff = current - previous;
  if (Math.abs(diff) < 0.001) return 'stable';
  return diff > 0 ? 'up' : 'down';
}

/**
 * Calculate fleet status distribution percentages
 */
export function calculateStatusPercentages(summary: FleetStatusSummary): {
  fit: number;
  inMaintenance: number;
  outOfService: number;
  restricted: number;
} {
  const total = summary.totalTrains;
  if (total === 0) {
    return { fit: 0, inMaintenance: 0, outOfService: 0, restricted: 0 };
  }

  return {
    fit: (summary.statusDistribution.fit / total) * 100,
    inMaintenance: (summary.statusDistribution.inMaintenance / total) * 100,
    outOfService: (summary.statusDistribution.outOfService / total) * 100,
    restricted: (summary.statusDistribution.restricted / total) * 100,
  };
}

/**
 * Get default widget configuration for a role
 */
export function getDefaultWidgetsForRole(role: DashboardRole): WidgetConfig[] {
  const baseWidgets: WidgetConfig[] = [
    { id: 'kpi_cards', title: 'Key Metrics', enabled: true, position: { row: 0, col: 0 }, size: { width: 12, height: 2 }, collapsed: false, refreshInterval: 60000 },
    { id: 'alerts', title: 'Alerts & Warnings', enabled: true, position: { row: 2, col: 6 }, size: { width: 6, height: 4 }, collapsed: false, refreshInterval: 30000 },
  ];

  switch (role) {
    case 'fleet_manager':
      return [
        ...baseWidgets,
        { id: 'fleet_status', title: 'Fleet Status', enabled: true, position: { row: 2, col: 0 }, size: { width: 6, height: 4 }, collapsed: false, refreshInterval: 60000 },
        { id: 'pm_timeline', title: 'PM Schedule', enabled: true, position: { row: 6, col: 0 }, size: { width: 12, height: 3 }, collapsed: false, refreshInterval: 300000 },
        { id: 'cost_compliance', title: 'Cost Compliance', enabled: true, position: { row: 9, col: 0 }, size: { width: 6, height: 4 }, collapsed: false, refreshInterval: 3600000 },
      ];

    case 'maintenance_planner':
      return [
        ...baseWidgets,
        { id: 'pm_timeline', title: 'PM Schedule', enabled: true, position: { row: 2, col: 0 }, size: { width: 6, height: 4 }, collapsed: false, refreshInterval: 300000 },
        { id: 'resource_chart', title: 'Resource Utilisation', enabled: true, position: { row: 6, col: 0 }, size: { width: 12, height: 4 }, collapsed: false, refreshInterval: 300000 },
        { id: 'mileage_variance', title: 'Mileage Variance', enabled: true, position: { row: 10, col: 0 }, size: { width: 6, height: 3 }, collapsed: false, refreshInterval: 300000 },
      ];

    case 'operations_manager':
      return [
        ...baseWidgets,
        { id: 'run_assignments', title: "Today's Assignments", enabled: true, position: { row: 2, col: 0 }, size: { width: 6, height: 4 }, collapsed: false, refreshInterval: 60000 },
        { id: 'fleet_status', title: 'Fleet Status', enabled: true, position: { row: 6, col: 0 }, size: { width: 6, height: 4 }, collapsed: false, refreshInterval: 60000 },
        { id: 'mileage_variance', title: 'Mileage Balance', enabled: true, position: { row: 6, col: 6 }, size: { width: 6, height: 4 }, collapsed: false, refreshInterval: 300000 },
      ];

    case 'executive':
      return [
        { id: 'kpi_cards', title: 'Key Metrics', enabled: true, position: { row: 0, col: 0 }, size: { width: 12, height: 3 }, collapsed: false, refreshInterval: 300000 },
        { id: 'cost_compliance', title: 'Cost Overview', enabled: true, position: { row: 3, col: 0 }, size: { width: 6, height: 4 }, collapsed: false, refreshInterval: 3600000 },
        { id: 'fleet_status', title: 'Fleet Summary', enabled: true, position: { row: 3, col: 6 }, size: { width: 6, height: 4 }, collapsed: false, refreshInterval: 300000 },
      ];

    case 'technician_supervisor':
      return [
        ...baseWidgets,
        { id: 'run_assignments', title: "Today's Work", enabled: true, position: { row: 2, col: 0 }, size: { width: 6, height: 4 }, collapsed: false, refreshInterval: 60000 },
        { id: 'pm_timeline', title: 'This Week Schedule', enabled: true, position: { row: 6, col: 0 }, size: { width: 12, height: 3 }, collapsed: false, refreshInterval: 300000 },
      ];

    default:
      return baseWidgets;
  }
}

