   242вҶ’/**
   243вҶ’ * Default pagination
   244вҶ’ */
   245вҶ’export const DEFAULT_PAGINATION: Omit<PaginationState, 'totalItems' | 'totalPages'> = {
   246вҶ’  currentPage: 1,
   247вҶ’  pageSize: 25,
