   249вҶ’
   250вҶ’// ============================================================================
   251вҶ’// Selection Types
   252вҶ’// ============================================================================
   253вҶ’
   254вҶ’/**
   255вҶ’ * Row selection state
   256вҶ’ */
   257вҶ’export interface SelectionState {
   258вҶ’  selectedIds: Set<string>;
   259вҶ’  isAllSelected: boolean;
   260вҶ’  isAllOnPageSelected: boolean;
   261вҶ’}
   262вҶ’
   263вҶ’/**
   264вҶ’ * Bulk action type
   265вҶ’ */
   266вҶ’export type BulkActionType = 'schedule_pm' | 'export' | 'assign' | 'clear';
   267вҶ’
   268вҶ’/**
   269вҶ’ * Bulk action configuration
   270вҶ’ */
   271вҶ’export interface BulkAction {
   272вҶ’  id: BulkActionType;
   273вҶ’  label: string;
   274вҶ’  icon: string;
   275вҶ’  requiresConfirmation: boolean;
   276вҶ’  minSelection?: number;
   277вҶ’  maxSelection?: number;
   278вҶ’}
   279вҶ’
   280вҶ’/**
   281вҶ’ * Available bulk actions
   282вҶ’ */
   283вҶ’export const BULK_ACTIONS: BulkAction[] = [
   284вҶ’  { id: 'schedule_pm', label: 'Schedule PM', icon: 'calendar', requiresConfirmation: true },
   285вҶ’  { id: 'export', label: 'Export', icon: 'download', requiresConfirmation: false },
   286вҶ’  { id: 'assign', label: 'Assign Route', icon: 'route', requiresConfirmation: true },
   287вҶ’  { id: 'clear', label: 'Clear Selection', icon: 'close', requiresConfirmation: false },
   288вҶ’];
   289вҶ’
   290вҶ’// ============================================================================
   291вҶ’// Row Action Types
   292вҶ’// ============================================================================
   293вҶ’
   294вҶ’/**
   295вҶ’ * Row action type
   296вҶ’ */
   297вҶ’export type RowActionType =
   298вҶ’  | 'view_details'
   299вҶ’  | 'schedule_pm'
   300вҶ’  | 'edit_assignment'
   301вҶ’  | 'mileage_history'
   302вҶ’  | 'open_maximo';
   303вҶ’
   304вҶ’/**
   305вҶ’ * Row action configuration
   306вҶ’ */
   307вҶ’export interface RowAction {
   308вҶ’  id: RowActionType;
   309вҶ’  label: string;
   310вҶ’  icon: string;
   311вҶ’  separator?: boolean;
   312вҶ’  requiresPermission?: string;
   313вҶ’  disabled?: (row: TrainGridRow) => boolean;
   314вҶ’}
   315вҶ’
   316вҶ’/**
   317вҶ’ * Available row actions
   318вҶ’ */
   319вҶ’export const ROW_ACTIONS: RowAction[] = [
   320вҶ’  { id: 'view_details', label: 'View Details', icon: 'info' },
   321вҶ’  { id: 'schedule_pm', label: 'Schedule PM', icon: 'calendar' },
   322вҶ’  { id: 'edit_assignment', label: 'Edit Assignment', icon: 'edit' },
   323вҶ’  { id: 'mileage_history', label: 'Mileage History', icon: 'chart' },
   324вҶ’  { id: 'open_maximo', label: 'Open in Maximo', icon: 'external_link', separator: true },
   325вҶ’];
   326вҶ’
   327вҶ’// ============================================================================
   328вҶ’// Grid Row Types
   329вҶ’// ============================================================================
   330вҶ’
   331вҶ’/**
   332вҶ’ * Train grid row data
   333вҶ’ */
   334вҶ’export interface TrainGridRow {
   335вҶ’  id: string;
   336вҶ’  trainId: string;
   337вҶ’  name: string;
   338вҶ’  fleetType: FleetType;
   339вҶ’  currentMileage: number;
   340вҶ’  lifetimeMileage: number;
   341вҶ’  pmWindow: PMWindowData;
   342вҶ’  fitnessStatus: FitnessStatus;
   343вҶ’  trainStatus: TrainStatus;
   344вҶ’  nextPM: {
   345вҶ’    level: PMLevel;
   346вҶ’    daysRemaining: number;
   347вҶ’    estimatedDate: Date;
   348вҶ’  };
   349вҶ’  lastService: Date;
   350вҶ’  assignment?: {
   351вҶ’    routeId: string;
   352вҶ’    routeName: string;
   353вҶ’    estimatedKm: number;
   354вҶ’  };
   355вҶ’  baseDepot: string;
   356вҶ’  notes?: string;
   357вҶ’  lastUpdated: Date;
   358вҶ’}
   359вҶ’
   360вҶ’/**
   361вҶ’ * Row styling state
   362вҶ’ */
   363вҶ’export type RowState = 'default' | 'hover' | 'selected' | 'critical';
   364вҶ’
   365вҶ’/**
   366вҶ’ * Row styling configuration
   367вҶ’ */
   368вҶ’export const ROW_STYLES: Record<RowState, {
   369вҶ’  background: string;
   370вҶ’  borderLeft?: string;
   371вҶ’}> = {
   372вҶ’  default: { background: '#FFFFFF' },
   373вҶ’  hover: { background: '#F3F4F6' },
   374вҶ’  selected: { background: '#DBEAFE', borderLeft: '3px solid #3B82F6' },
   375вҶ’  critical: { background: '#FEE2E2' },
   376вҶ’};
   377вҶ’
   378вҶ’// ============================================================================
   379вҶ’// Summary Types
   380вҶ’// ============================================================================
   381вҶ’
   382вҶ’/**
   383вҶ’ * Fleet summary counts for summary bar
   384вҶ’ */
   385вҶ’export interface FleetSummaryCounts {
   386вҶ’  total: number;
   387вҶ’  byFitness: Record<FitnessStatus, number>;
   388вҶ’  byStatus: Record<TrainStatus, number>;
   389вҶ’  pmDueThisWeek: number;
   390вҶ’  pmOverdue: number;
   391вҶ’}
   392вҶ’
   393вҶ’// ============================================================================
   394вҶ’// Grid State Types
   395вҶ’// ============================================================================
   396вҶ’
   397вҶ’/**
   398вҶ’ * Complete grid state
   399вҶ’ */
   400вҶ’export interface TrainGridState {
   401вҶ’  // Data
   402вҶ’  rows: TrainGridRow[];
   403вҶ’  filteredRows: TrainGridRow[];
   404вҶ’  isLoading: boolean;
   405вҶ’  error?: string;
   406вҶ’
   407вҶ’  // Display
   408вҶ’  columns: TrainGridColumn[];
   409вҶ’  viewMode: 'table' | 'card';
   410вҶ’
   411вҶ’  // Filtering
   412вҶ’  filters: TrainGridFilters;
   413вҶ’  activeFilterChips: FilterChip[];
   414вҶ’
   415вҶ’  // Sorting
   416вҶ’  sort: ColumnSort[];
   417вҶ’
   418вҶ’  // Pagination
   419вҶ’  pagination: PaginationState;
   420вҶ’
   421вҶ’  // Selection
   422вҶ’  selection: SelectionState;
   423вҶ’
   424вҶ’  // Summary
   425вҶ’  summary: FleetSummaryCounts;
   426вҶ’
   427вҶ’  // Metadata
   428вҶ’  lastRefreshed: Date;
   429вҶ’  isStale: boolean;
   430вҶ’}
   431вҶ’
   432вҶ’// ============================================================================
   433вҶ’// Helper Functions
   434вҶ’// ============================================================================
   435вҶ’
   436вҶ’/**
   437вҶ’ * Determine PM window status from percentage
   438вҶ’ */
   439вҶ’export function getPMWindowStatus(percentComplete: number): PMWindowStatus {
   440вҶ’  if (percentComplete >= 100) return 'OVERDUE';
   441вҶ’  if (percentComplete >= 95) return 'CRITICAL';
   442вҶ’  if (percentComplete >= 80) return 'APPROACHING';
   443вҶ’  return 'SAFE';
   444вҶ’}
   445вҶ’
   446вҶ’/**
   447вҶ’ * Calculate PM window data from train
   448вҶ’ */
   449вҶ’export function calculatePMWindow(
   450вҶ’  currentMileage: number,
   451вҶ’  targetMileage: number,
   452вҶ’  dailyAverage: number
   453вҶ’): PMWindowData {
   454вҶ’  const percentComplete = (currentMileage / targetMileage) * 100;
   455вҶ’  const kmRemaining = Math.max(0, targetMileage - currentMileage);
   456вҶ’  const daysRemaining = dailyAverage > 0 ? Math.ceil(kmRemaining / dailyAverage) : 999;
   457вҶ’
   458вҶ’  return {
   459вҶ’    level: 'PM1', // Will be set by caller
   460вҶ’    targetMileage,
   461вҶ’    currentMileage,
   462вҶ’    percentComplete: Math.min(100, percentComplete),
   463вҶ’    kmRemaining,
   464вҶ’    status: getPMWindowStatus(percentComplete),
   465вҶ’    daysRemaining,
   466вҶ’  };
   467вҶ’}
   468вҶ’
   469вҶ’/**
   470вҶ’ * Format mileage for display
   471вҶ’ */
   472вҶ’export function formatMileage(km: number): string {
   473вҶ’  if (km >= 1000) {
   474вҶ’    return `${(km / 1000).toFixed(1)}k km`;
   475вҶ’  }
   476вҶ’  return `${km.toLocaleString()} km`;
   477вҶ’}
   478вҶ’
   479вҶ’/**
   480вҶ’ * Format days remaining for display
   481вҶ’ */
   482вҶ’export function formatDaysRemaining(days: number): string {
   483вҶ’  if (days <= 0) return 'Overdue';
   484вҶ’  if (days === 1) return '1 day';
   485вҶ’  if (days < 7) return `${days} days`;
   486вҶ’  if (days < 30) return `${Math.ceil(days / 7)} weeks`;
   487вҶ’  return `${Math.ceil(days / 30)} months`;
   488вҶ’}
   489вҶ’
   490вҶ’/**
   491вҶ’ * Get filter chips from current filter state
   492вҶ’ */
   493вҶ’export function getFilterChips(filters: TrainGridFilters): FilterChip[] {
   494вҶ’  const chips: FilterChip[] = [];
   495вҶ’
   496вҶ’  if (filters.fleet !== 'ALL') {
   497вҶ’    chips.push({
   498вҶ’      id: 'fleet',
   499вҶ’      label: filters.fleet === 'KINKI_SHARYO' ? 'Kinki Sharyo' : 'Alstom',
   500вҶ’      filterKey: 'fleet',
   501вҶ’      value: filters.fleet,
   502вҶ’      removable: true,
   503вҶ’    });
   504вҶ’  }
   505вҶ’
   506вҶ’  if (filters.status !== 'ALL') {
   507вҶ’    chips.push({
   508вҶ’      id: 'status',
   509вҶ’      label: filters.status,
   510вҶ’      filterKey: 'status',
   511вҶ’      value: filters.status,
   512вҶ’      removable: true,
   513вҶ’    });
   514вҶ’  }
   515вҶ’
   516вҶ’  if (filters.pmDue !== 'ALL') {
   517вҶ’    const labels: Record<PMDueFilterOption, string> = {
   518вҶ’      ALL: 'All',
   519вҶ’      OVERDUE: 'Overdue',
   520вҶ’      THIS_WEEK: 'Due This Week',
   521вҶ’      THIS_MONTH: 'Due This Month',
   522вҶ’      NEXT_3_MONTHS: 'Due in 3 Months',
   523вҶ’    };
   524вҶ’    chips.push({
   525вҶ’      id: 'pmDue',
   526вҶ’      label: labels[filters.pmDue],
   527вҶ’      filterKey: 'pmDue',
   528вҶ’      value: filters.pmDue,
   529вҶ’      removable: true,
   530вҶ’    });
   531вҶ’  }
   532вҶ’
   533вҶ’  if (filters.search) {
   534вҶ’    chips.push({
   535вҶ’      id: 'search',
   536вҶ’      label: `"${filters.search}"`,
   537вҶ’      filterKey: 'search',
   538вҶ’      value: filters.search,
   539вҶ’      removable: true,
   540вҶ’    });
   541вҶ’  }
   542вҶ’
   543вҶ’  return chips;
   544вҶ’}
   545вҶ’
   546вҶ’/**
   547вҶ’ * Calculate summary counts from rows
   548вҶ’ */
   549вҶ’export function calculateSummaryCounts(rows: TrainGridRow[]): FleetSummaryCounts {
   550вҶ’  const summary: FleetSummaryCounts = {
   551вҶ’    total: rows.length,
   552вҶ’    byFitness: { FIT: 0, RESTRICTED: 0, UNFIT: 0 },
   553вҶ’    byStatus: { IN_SERVICE: 0, IN_MAINTENANCE: 0, OUT_OF_SERVICE: 0, RESERVED: 0 },
   554вҶ’    pmDueThisWeek: 0,
   555вҶ’    pmOverdue: 0,
   556вҶ’  };
   557вҶ’
   558вҶ’  for (const row of rows) {
   559вҶ’    summary.byFitness[row.fitnessStatus]++;
   560вҶ’    summary.byStatus[row.trainStatus]++;
   561вҶ’
   562вҶ’    if (row.pmWindow.status === 'OVERDUE') {
   563вҶ’      summary.pmOverdue++;
   564вҶ’    } else if (row.nextPM.daysRemaining <= 7) {
   565вҶ’      summary.pmDueThisWeek++;
   566вҶ’    }
   567вҶ’  }
   568вҶ’
   569вҶ’  return summary;
   570вҶ’}
