   360вҶ’  allowCritical: boolean; // P1 alerts still delivered
   361вҶ’}
   362вҶ’
   363вҶ’/**
   364вҶ’ * Daily digest configuration
   365вҶ’ */
   366вҶ’export interface DailyDigestConfig {
   367вҶ’  enabled: boolean;
   368вҶ’  deliveryTime: string; // HH:mm format
