   500вҶ’export const SNOOZE_DURATIONS: SnoozeDurationConfig[] = [
   501вҶ’  { duration: '15_MINUTES', label: '15 minutes', minutes: 15 },
   502вҶ’  { duration: '1_HOUR', label: '1 hour', minutes: 60 },
   503вҶ’  { duration: '4_HOURS', label: '4 hours', minutes: 240 },
   504вҶ’  { duration: 'TOMORROW_MORNING', label: 'Tomorrow morning (9:00 AM)' },
   505вҶ’  { duration: 'CUSTOM', label: 'Custom...' },
