   521вҶ’
   522вҶ’/**
   523вҶ’ * Notification center filter
   524вҶ’ */
   525вҶ’export interface NotificationFilter {
   526вҶ’  category?: AlertCategory[];
   527вҶ’  priority?: AlertPriority[];
   528вҶ’  status?: NotificationStatus[];
   529вҶ’  dateRange?: {
   530вҶ’    start: Date;
   531вҶ’    end: Date;
   532вҶ’  };
   533вҶ’  searchQuery?: string;
   534вҶ’}
   535вҶ’
   536вҶ’/**
   537вҶ’ * Notification center sort options
   538вҶ’ */
   539вҶ’export type NotificationSortField = 'createdAt' | 'priority' | 'category' | 'status';
   540вҶ’
   541вҶ’/**
   542вҶ’ * Notification center tab
   543вҶ’ */
   544вҶ’export type NotificationTab = 'ALL' | 'UNREAD' | 'CRITICAL' | 'ACTIONS';
   545вҶ’
   546вҶ’/**
   547вҶ’ * Notification center state
   548вҶ’ */
   549вҶ’export interface NotificationCenterState {
