   576вҶ’
   577вҶ’/**
   578вҶ’ * Subscriptions editor state
   579вҶ’ */
   580вҶ’export interface SubscriptionsEditorState {
   581вҶ’  subscriptions: AlertSubscription[];
   582вҶ’  isLoading: boolean;
   583вҶ’  isAdding: boolean;
   584вҶ’  error?: string;
   585вҶ’}
   586вҶ’
   587вҶ’// ============================================================================
   588вҶ’// Toast State Types
   589вҶ’// ============================================================================
   590вҶ’
   591вҶ’/**
   592вҶ’ * Toast position
   593вҶ’ */
   594вҶ’export type ToastPosition =
   595вҶ’  | 'TOP_LEFT'
   596вҶ’  | 'TOP_CENTER'
   597вҶ’  | 'TOP_RIGHT'
   598вҶ’  | 'BOTTOM_LEFT'
   599вҶ’  | 'BOTTOM_CENTER'
   600вҶ’  | 'BOTTOM_RIGHT';
   601вҶ’
   602вҶ’/**
   603вҶ’ * Toast notification for immediate display
   604вҶ’ */
   605вҶ’export interface Toast {
   606вҶ’  id: string;
   607вҶ’  priority: AlertPriority;
   608вҶ’  title: string;
   609вҶ’  body?: string;
   610вҶ’  action?: NotificationAction;
   611вҶ’  autoDismiss: boolean;
   612вҶ’  duration: number; // milliseconds
   613вҶ’  createdAt: Date;
   614вҶ’}
   615вҶ’
   616вҶ’/**
   617вҶ’ * Toast container state
   618вҶ’ */
   619вҶ’export interface ToastContainerState {
   620вҶ’  toasts: Toast[];
   621вҶ’  position: ToastPosition;
   622вҶ’  maxVisible: number;
   623вҶ’}
   624вҶ’
   625вҶ’// ============================================================================
   626вҶ’// Analytics Types
   627вҶ’// ============================================================================
   628вҶ’
   629вҶ’/**
   630вҶ’ * Alert analytics metrics
   631вҶ’ */
   632вҶ’export interface AlertAnalytics {
   633вҶ’  period: {
   634вҶ’    start: Date;
   635вҶ’    end: Date;
   636вҶ’  };
   637вҶ’  totalAlerts: number;
