   664вҶ’  data: Record<string, unknown>;
   665вҶ’  actions: Array<{
   666вҶ’    id: string;
   667вҶ’    label: string;
   668вҶ’    url: string;
   669вҶ’  }>;
   670вҶ’}
   671вҶ’
   672вҶ’// ============================================================================
   673вҶ’// Helper Functions
   674вҶ’// ============================================================================
   675вҶ’
   676вҶ’/**
   677вҶ’ * Get priority configuration
   678вҶ’ */
   679вҶ’export function getPriorityConfig(priority: AlertPriority): AlertPriorityConfig {
   680вҶ’  return { priority, ...ALERT_PRIORITY_CONFIG[priority] };
   681вҶ’}
   682вҶ’
   683вҶ’/**
   684вҶ’ * Get category configuration
   685вҶ’ */
   686вҶ’export function getCategoryConfig(category: AlertCategory): AlertCategoryConfig {
   687вҶ’  return { category, ...ALERT_CATEGORY_CONFIG[category] };
   688вҶ’}
   689вҶ’
   690вҶ’/**
   691вҶ’ * Format time ago string
   692вҶ’ */
   693вҶ’export function formatTimeAgo(date: Date): string {
   694вҶ’  const now = new Date();
   695вҶ’  const diffMs = now.getTime() - date.getTime();
   696вҶ’  const diffMinutes = Math.floor(diffMs / 60000);
   697вҶ’  const diffHours = Math.floor(diffMinutes / 60);
   698вҶ’  const diffDays = Math.floor(diffHours / 24);
   699вҶ’
   700вҶ’  if (diffMinutes < 1) return 'Just now';
   701вҶ’  if (diffMinutes < 60) return `${diffMinutes} min ago`;
   702вҶ’  if (diffHours < 24) return `${diffHours} hr ago`;
   703вҶ’  if (diffDays === 1) return 'Yesterday';
   704вҶ’  if (diffDays < 7) return `${diffDays} days ago`;
   705вҶ’  return date.toLocaleDateString();
   706вҶ’}
   707вҶ’
   708вҶ’/**
   709вҶ’ * Check if notification can be acknowledged
   710вҶ’ */
   711вҶ’export function canAcknowledgeNotification(notification: Notification): boolean {
   712вҶ’  return (
   713вҶ’    notification.status === 'UNREAD' ||
   714вҶ’    notification.status === 'READ' ||
   715вҶ’    notification.status === 'ESCALATED'
   716вҶ’  );
   717вҶ’}
   718вҶ’
   719вҶ’/**
   720вҶ’ * Check if notification can be snoozed
   721вҶ’ */
   722вҶ’export function canSnoozeNotification(notification: Notification): boolean {
   723вҶ’  return (
   724вҶ’    notification.priority !== 'P1' &&
   725вҶ’    (notification.status === 'UNREAD' || notification.status === 'READ')
   726вҶ’  );
   727вҶ’}
   728вҶ’
   729вҶ’/**
   730вҶ’ * Check if notification can be resolved
   731вҶ’ */
   732вҶ’export function canResolveNotification(notification: Notification): boolean {
   733вҶ’  return notification.status !== 'RESOLVED';
   734вҶ’}
   735вҶ’
   736вҶ’/**
   737вҶ’ * Convert notification to list item
   738вҶ’ */
   739вҶ’export function toNotificationListItem(notification: Notification): NotificationListItem {
   740вҶ’  return {
   741вҶ’    ...notification,
   742вҶ’    timeAgo: formatTimeAgo(notification.createdAt),
   743вҶ’    priorityConfig: getPriorityConfig(notification.priority),
   744вҶ’    categoryConfig: getCategoryConfig(notification.category),
   745вҶ’    isUnread: notification.status === 'UNREAD',
   746вҶ’    canAcknowledge: canAcknowledgeNotification(notification),
   747вҶ’    canSnooze: canSnoozeNotification(notification),
   748вҶ’    canResolve: canResolveNotification(notification),
   749вҶ’  };
   750вҶ’}
   751вҶ’
   752вҶ’/**
   753вҶ’ * Calculate snooze until date
   754вҶ’ */
   755вҶ’export function calculateSnoozeUntil(duration: SnoozeDuration, customMinutes?: number): Date {
   756вҶ’  const now = new Date();
   757вҶ’
   758вҶ’  switch (duration) {
   759вҶ’    case '15_MINUTES':
   760вҶ’      return new Date(now.getTime() + 15 * 60 * 1000);
   761вҶ’    case '1_HOUR':
   762вҶ’      return new Date(now.getTime() + 60 * 60 * 1000);
   763вҶ’    case '4_HOURS':
   764вҶ’      return new Date(now.getTime() + 4 * 60 * 60 * 1000);
   765вҶ’    case 'TOMORROW_MORNING': {
   766вҶ’      const tomorrow = new Date(now);
   767вҶ’      tomorrow.setDate(tomorrow.getDate() + 1);
   768вҶ’      tomorrow.setHours(9, 0, 0, 0);
   769вҶ’      return tomorrow;
   770вҶ’    }
   771вҶ’    case 'CUSTOM':
   772вҶ’      return new Date(now.getTime() + (customMinutes || 60) * 60 * 1000);
   773вҶ’    default:
   774вҶ’      return new Date(now.getTime() + 60 * 60 * 1000);
   775вҶ’  }
   776вҶ’}
   777вҶ’
   778вҶ’/**
   779вҶ’ * Check if current time is within quiet hours
   780вҶ’ */
   781вҶ’export function isWithinQuietHours(config: QuietHoursConfig): boolean {
   782вҶ’  if (!config.enabled) return false;
   783вҶ’
   784вҶ’  const now = new Date();
   785вҶ’  const currentMinutes = now.getHours() * 60 + now.getMinutes();
   786вҶ’
   787вҶ’  const [startHour, startMin] = config.startTime.split(':').map(Number);
   788вҶ’  const [endHour, endMin] = config.endTime.split(':').map(Number);
   789вҶ’
   790вҶ’  const startMinutes = startHour * 60 + startMin;
   791вҶ’  const endMinutes = endHour * 60 + endMin;
   792вҶ’
   793вҶ’  // Handle overnight quiet hours (e.g., 22:00 - 07:00)
   794вҶ’  if (startMinutes > endMinutes) {
   795вҶ’    return currentMinutes >= startMinutes || currentMinutes < endMinutes;
   796вҶ’  }
   797вҶ’
   798вҶ’  return currentMinutes >= startMinutes && currentMinutes < endMinutes;
   799вҶ’}
   800вҶ’
   801вҶ’/**
   802вҶ’ * Get badge display value
   803вҶ’ */
   804вҶ’export function getBadgeDisplay(count: number): string {
   805вҶ’  if (count === 0) return '';
   806вҶ’  if (count > 99) return '99+';
   807вҶ’  return count.toString();
   808вҶ’}
   809вҶ’
   810вҶ’/**
   811вҶ’ * Create default toast
   812вҶ’ */
   813вҶ’export function createToast(
   814вҶ’  priority: AlertPriority,
   815вҶ’  title: string,
   816вҶ’  body?: string,
   817вҶ’  action?: NotificationAction
   818вҶ’): Toast {
   819вҶ’  return {
   820вҶ’    id: `toast-${Date.now()}`,
   821вҶ’    priority,
   822вҶ’    title,
   823вҶ’    body,
   824вҶ’    action,
   825вҶ’    autoDismiss: priority !== 'P1',
   826вҶ’    duration: priority === 'P1' ? 10000 : 5000,
   827вҶ’    createdAt: new Date(),
   828вҶ’  };
   829вҶ’}
   830вҶ’
   831вҶ’/**
   832вҶ’ * Group notifications by date
   833вҶ’ */
   834вҶ’export function groupNotificationsByDate(
   835вҶ’  notifications: NotificationListItem[]
   836вҶ’): Map<string, NotificationListItem[]> {
   837вҶ’  const groups = new Map<string, NotificationListItem[]>();
   838вҶ’  const today = new Date();
   839вҶ’  today.setHours(0, 0, 0, 0);
   840вҶ’  const yesterday = new Date(today);
   841вҶ’  yesterday.setDate(yesterday.getDate() - 1);
   842вҶ’
   843вҶ’  for (const notification of notifications) {
   844вҶ’    const notifDate = new Date(notification.createdAt);
   845вҶ’    notifDate.setHours(0, 0, 0, 0);
   846вҶ’
   847вҶ’    let key: string;
   848вҶ’    if (notifDate.getTime() === today.getTime()) {
   849вҶ’      key = 'Today';
   850вҶ’    } else if (notifDate.getTime() === yesterday.getTime()) {
   851вҶ’      key = 'Yesterday';
   852вҶ’    } else {
   853вҶ’      key = notifDate.toLocaleDateString('en-US', {
   854вҶ’        weekday: 'long',
   855вҶ’        month: 'short',
   856вҶ’        day: 'numeric',
   857вҶ’      });
   858вҶ’    }
   859вҶ’
   860вҶ’    const existing = groups.get(key) || [];
   861вҶ’    existing.push(notification);
   862вҶ’    groups.set(key, existing);
   863вҶ’  }
   864вҶ’
   865вҶ’  return groups;
   866вҶ’}
