/**
 * Alert & Notification System UI Types
 *
 * TypeScript types for the alert and notification module.
 * Based on UX specification MILEAGE-UX-009.
 */

import type { FleetType, Train } from './train';

// ============================================================================
// Priority & Category Types
// ============================================================================

/**
 * Alert priority levels (P1-P4)
 */
export type AlertPriority = 'P1' | 'P2' | 'P3' | 'P4';

/**
 * Priority configuration
 */
export interface AlertPriorityConfig {
  priority: AlertPriority;
  label: string;
  color: string;
  icon: string;
  responseTime: string;
  autoEscalateMinutes: number | null;
}

/**
 * Priority configurations
 */
export const ALERT_PRIORITY_CONFIG: Record<AlertPriority, Omit<AlertPriorityConfig, 'priority'>> = {
  P1: {
    label: 'Critical',
    color: '#DC2626',
    icon: '!',
    responseTime: 'Immediate',
    autoEscalateMinutes: 15,
  },
  P2: {
    label: 'Warning',
    color: '#F59E0B',
    icon: '!',
    responseTime: '4 hours',
    autoEscalateMinutes: 24 * 60, // 24 hours
  },
  P3: {
    label: 'Info',
    color: '#3B82F6',
    icon: 'i',
    responseTime: '24 hours',
    autoEscalateMinutes: null,
  },
  P4: {
    label: 'Success',
    color: '#22C55E',
    icon: 'вң“',
    responseTime: 'N/A',
    autoEscalateMinutes: null,
  },
};

/**
 * Alert categories
 */
export type AlertCategory =
  | 'MAINTENANCE'
  | 'MILEAGE'
  | 'ASSIGNMENT'
  | 'RESOURCE'
  | 'COST'
  | 'SYSTEM';

/**
 * Category configuration
 */
export interface AlertCategoryConfig {
  category: AlertCategory;
  label: string;
  icon: string;
  color: string;
}

/**
 * Category configurations
 */
export const ALERT_CATEGORY_CONFIG: Record<AlertCategory, Omit<AlertCategoryConfig, 'category'>> = {
  MAINTENANCE: { label: 'Maintenance', icon: 'рҹ”§', color: '#3B82F6' },
  MILEAGE: { label: 'Mileage', icon: 'рҹ“Ҳ', color: '#22C55E' },
  ASSIGNMENT: { label: 'Assignment', icon: 'рҹҡӮ', color: '#8B5CF6' },
  RESOURCE: { label: 'Resource', icon: 'рҹ‘Ҙ', color: '#F59E0B' },
  COST: { label: 'Cost', icon: 'рҹ’°', color: '#EC4899' },
