// ============================================================================
// Subscription Types
// ============================================================================

/**
 * Subscription type
 */
export type SubscriptionType = 'FLEET' | 'TRAIN' | 'ROUTE';

/**
 * Subscription scope
 */
export type SubscriptionScope = 'ALL' | 'PM_ONLY' | 'MILEAGE_ONLY' | 'ASSIGNMENT_ONLY';

/**
 * Alert subscription
 */
export interface AlertSubscription {
