// ============================================================================
// Snooze Types
// ============================================================================

/**
 * Snooze duration presets
 */
export type SnoozeDuration =
  | '15_MINUTES'
  | '1_HOUR'
  | '4_HOURS'
  | 'TOMORROW_MORNING'
  | 'CUSTOM';

/**
 * Snooze duration configuration
 */
export interface SnoozeDurationConfig {
  duration: SnoozeDuration;
  label: string;
  minutes?: number;
}

/**
 * Snooze presets
 */
export const SNOOZE_DURATIONS: SnoozeDurationConfig[] = [
  { duration: '15_MINUTES', label: '15 minutes', minutes: 15 },
  { duration: '1_HOUR', label: '1 hour', minutes: 60 },
  { duration: '4_HOURS', label: '4 hours', minutes: 240 },
  { duration: 'TOMORROW_MORNING', label: 'Tomorrow morning (9:00 AM)' },
  { duration: 'CUSTOM', label: 'Custom...' },
];

/**
 * Snooze request
 */
export interface SnoozeRequest {
  notificationId: string;
