}

// ============================================================================
// UI State Types
// ============================================================================

/**
 * Notification center filter
 */
export interface NotificationFilter {
  category?: AlertCategory[];
  priority?: AlertPriority[];
  status?: NotificationStatus[];
  dateRange?: {
    start: Date;
    end: Date;
  };
  searchQuery?: string;
}

/**
 * Notification center sort options
 */
export type NotificationSortField = 'createdAt' | 'priority' | 'category' | 'status';

/**
 * Notification center tab
 */
export type NotificationTab = 'ALL' | 'UNREAD' | 'CRITICAL' | 'ACTIONS';

/**
 * Notification center state
 */
export interface NotificationCenterState {
  notifications: NotificationListItem[];
  activeTab: NotificationTab;
  filter: NotificationFilter;
  sort: {
    field: NotificationSortField;
    direction: 'ASC' | 'DESC';
  };
