}

/**
 * Subscriptions editor state
 */
export interface SubscriptionsEditorState {
  subscriptions: AlertSubscription[];
  isLoading: boolean;
  isAdding: boolean;
  error?: string;
}

// ============================================================================
// Toast State Types
// ============================================================================

/**
 * Toast position
 */
export type ToastPosition =
  | 'TOP_LEFT'
  | 'TOP_CENTER'
  | 'TOP_RIGHT'
  | 'BOTTOM_LEFT'
  | 'BOTTOM_CENTER'
  | 'BOTTOM_RIGHT';

/**
 * Toast notification for immediate display
 */
export interface Toast {
  id: string;
  priority: AlertPriority;
  title: string;
  body?: string;
  action?: NotificationAction;
  autoDismiss: boolean;
  duration: number; // milliseconds
  createdAt: Date;
}

/**
 * Toast container state
 */
export interface ToastContainerState {
  toasts: Toast[];
  position: ToastPosition;
  maxVisible: number;
}

// ============================================================================
// Analytics Types
// ============================================================================

/**
 * Alert analytics metrics
 */
export interface AlertAnalytics {
  period: {
    start: Date;
    end: Date;
  };
  totalAlerts: number;
  acknowledgedCount: number;
  acknowledgmentRate: number;
  byPriority: Record<AlertPriority, number>;
  byCategory: Record<AlertCategory, number>;
  avgResponseTimeMinutes: Record<AlertPriority, number>;
  escalationRate: number;
  dismissRate: number;
}

// ============================================================================
// Webhook Types
// ============================================================================

/**
 * Webhook payload for external integrations
 */
export interface NotificationWebhookPayload {
  id: string;
  timestamp: string; // ISO 8601
  priority: AlertPriority;
  category: AlertCategory;
  type: AlertType;
  title: string;
  body: string;
  trainId?: string;
  fleetType?: FleetType;
  data: Record<string, unknown>;
  actions: Array<{
    id: string;
    label: string;
    url: string;
  }>;
}

// ============================================================================
// Helper Functions
// ============================================================================

/**
 * Get priority configuration
 */
export function getPriorityConfig(priority: AlertPriority): AlertPriorityConfig {
  return { priority, ...ALERT_PRIORITY_CONFIG[priority] };
}

/**
 * Get category configuration
 */
export function getCategoryConfig(category: AlertCategory): AlertCategoryConfig {
  return { category, ...ALERT_CATEGORY_CONFIG[category] };
}

/**
 * Format time ago string
 */
export function formatTimeAgo(date: Date): string {
  const now = new Date();
  const diffMs = now.getTime() - date.getTime();
  const diffMinutes = Math.floor(diffMs / 60000);
  const diffHours = Math.floor(diffMinutes / 60);
  const diffDays = Math.floor(diffHours / 24);

  if (diffMinutes < 1) return 'Just now';
  if (diffMinutes < 60) return `${diffMinutes} min ago`;
  if (diffHours < 24) return `${diffHours} hr ago`;
  if (diffDays === 1) return 'Yesterday';
  if (diffDays < 7) return `${diffDays} days ago`;
  return date.toLocaleDateString();
}

/**
 * Check if notification can be acknowledged
 */
export function canAcknowledgeNotification(notification: Notification): boolean {
  return (
    notification.status === 'UNREAD' ||
    notification.status === 'READ' ||
    notification.status === 'ESCALATED'
  );
}

/**
 * Check if notification can be snoozed
 */
export function canSnoozeNotification(notification: Notification): boolean {
  return (
    notification.priority !== 'P1' &&
    (notification.status === 'UNREAD' || notification.status === 'READ')
  );
}

/**
 * Check if notification can be resolved
 */
export function canResolveNotification(notification: Notification): boolean {
  return notification.status !== 'RESOLVED';
}

/**
 * Convert notification to list item
 */
export function toNotificationListItem(notification: Notification): NotificationListItem {
  return {
    ...notification,
    timeAgo: formatTimeAgo(notification.createdAt),
    priorityConfig: getPriorityConfig(notification.priority),
    categoryConfig: getCategoryConfig(notification.category),
    isUnread: notification.status === 'UNREAD',
    canAcknowledge: canAcknowledgeNotification(notification),
    canSnooze: canSnoozeNotification(notification),
    canResolve: canResolveNotification(notification),
  };
}

/**
 * Calculate snooze until date
 */
export function calculateSnoozeUntil(duration: SnoozeDuration, customMinutes?: number): Date {
  const now = new Date();

  switch (duration) {
    case '15_MINUTES':
      return new Date(now.getTime() + 15 * 60 * 1000);
    case '1_HOUR':
      return new Date(now.getTime() + 60 * 60 * 1000);
    case '4_HOURS':
      return new Date(now.getTime() + 4 * 60 * 60 * 1000);
    case 'TOMORROW_MORNING': {
      const tomorrow = new Date(now);
      tomorrow.setDate(tomorrow.getDate() + 1);
      tomorrow.setHours(9, 0, 0, 0);
      return tomorrow;
    }
    case 'CUSTOM':
      return new Date(now.getTime() + (customMinutes || 60) * 60 * 1000);
    default:
      return new Date(now.getTime() + 60 * 60 * 1000);
  }
}

/**
 * Check if current time is within quiet hours
 */
export function isWithinQuietHours(config: QuietHoursConfig): boolean {
  if (!config.enabled) return false;

  const now = new Date();
  const currentMinutes = now.getHours() * 60 + now.getMinutes();

  const [startHour, startMin] = config.startTime.split(':').map(Number);
  const [endHour, endMin] = config.endTime.split(':').map(Number);

  const startMinutes = startHour * 60 + startMin;
  const endMinutes = endHour * 60 + endMin;

  // Handle overnight quiet hours (e.g., 22:00 - 07:00)
  if (startMinutes > endMinutes) {
    return currentMinutes >= startMinutes || currentMinutes < endMinutes;
  }

  return currentMinutes >= startMinutes && currentMinutes < endMinutes;
}

/**
 * Get badge display value
 */
export function getBadgeDisplay(count: number): string {
  if (count === 0) return '';
  if (count > 99) return '99+';
  return count.toString();
}

/**
 * Create default toast
 */
export function createToast(
  priority: AlertPriority,
  title: string,
  body?: string,
  action?: NotificationAction
): Toast {
  return {
    id: `toast-${Date.now()}`,
    priority,
    title,
    body,
    action,
    autoDismiss: priority !== 'P1',
    duration: priority === 'P1' ? 10000 : 5000,
    createdAt: new Date(),
  };
}

/**
 * Group notifications by date
 */
export function groupNotificationsByDate(
  notifications: NotificationListItem[]
): Map<string, NotificationListItem[]> {
  const groups = new Map<string, NotificationListItem[]>();
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  const yesterday = new Date(today);
  yesterday.setDate(yesterday.getDate() - 1);

  for (const notification of notifications) {
    const notifDate = new Date(notification.createdAt);
    notifDate.setHours(0, 0, 0, 0);

    let key: string;
    if (notifDate.getTime() === today.getTime()) {
      key = 'Today';
    } else if (notifDate.getTime() === yesterday.getTime()) {
      key = 'Yesterday';
    } else {
      key = notifDate.toLocaleDateString('en-US', {
        weekday: 'long',
        month: 'short',
        day: 'numeric',
      });
    }

    const existing = groups.get(key) || [];
    existing.push(notification);
    groups.set(key, existing);
  }

  return groups;
}

