## 4. Mock Data Strategy

### 4.1 Fixtures Structure

Based on [MSW best practices](https://mswjs.io/docs/), create reusable fixtures:

```typescript
// src/mocks/fixtures/trains.ts
import type { Train, FleetType } from '../../types';

// Generate 128 trains (49 Kinki Sharyo + 79 Alstom)
export function generateFleet(): Train[] {
  const trains: Train[] = [];

  // Kinki Sharyo fleet (KS-001 to KS-049)
  for (let i = 1; i <= 49; i++) {
    trains.push(generateTrain(`KS-${String(i).padStart(3, '0')}`, 'KINKI_SHARYO'));
  }

  // Alstom fleet (AL-001 to AL-079)
  for (let i = 1; i <= 79; i++) {
    trains.push(generateTrain(`AL-${String(i).padStart(3, '0')}`, 'ALSTOM'));
  }

  return trains;
}

function generateTrain(id: string, fleetType: FleetType): Train {
  const baseLifetimeMileage = fleetType === 'KINKI_SHARYO' 
    ? randomBetween(800000, 1200000) 
    : randomBetween(400000, 800000);

  return {
    id,
    name: `Train ${id}`,
    fleetType,
    lifetimeMileage: baseLifetimeMileage,
    currentMileage: randomBetween(0, 15000),
    fitnessStatus: randomFitnessStatus(),
    status: randomTrainStatus(),
    commissionedDate: randomPastDate(5),
    baseDepot: fleetType === 'KINKI_SHARYO' ? 'Depot A' : 'Depot B',
    // ... other fields
  };
}

// Pre-generated fleet for consistent tests
export const mockFleet = generateFleet();
export const mockKinkiFleet = mockFleet.filter(t => t.fleetType === 'KINKI_SHARYO');
export const mockAlstomFleet = mockFleet.filter(t => t.fleetType === 'ALSTOM');
```

```typescript
// src/mocks/fixtures/mileage.ts
import type { MileageRecord } from '../../types';
import { mockFleet } from './trains';

// Generate 144 months (12 years) of mileage history per train
export function generateMileageHistory(trainId: string, months = 144): MileageRecord[] {
  const records: MileageRecord[] = [];
  const startDate = new Date();
  startDate.setMonth(startDate.getMonth() - months);

  for (let i = 0; i < months; i++) {
    const date = new Date(startDate);
    date.setMonth(date.getMonth() + i);

    records.push({
      trainId,
      date,
      dailyMileage: randomBetween(200, 500),
      cumulativeMileage: calculateCumulative(i),
      source: 'MAXIMO_FEED',
    });
  }

  return records;
}

// Generate for all 128 trains
export const mockMileageHistory = mockFleet.reduce((acc, train) => {
  acc[train.id] = generateMileageHistory(train.id);
  return acc;
}, {} as Record<string, MileageRecord[]>);
```

### 4.2 MSW Request Handlers

Following the [MSW Storybook addon](https://storybook.js.org/addons/msw-storybook-addon) pattern:

```typescript
// src/mocks/handlers/trains.ts
import { http, HttpResponse, delay } from 'msw';
import { mockFleet, mockKinkiFleet, mockAlstomFleet } from '../fixtures/trains';

export const trainHandlers = [
  // GET /api/trains
  http.get('/api/trains', async ({ request }) => {
    await delay(150);
    const url = new URL(request.url);
    const fleet = url.searchParams.get('fleet');

    if (fleet === 'KINKI_SHARYO') return HttpResponse.json(mockKinkiFleet);
    if (fleet === 'ALSTOM') return HttpResponse.json(mockAlstomFleet);

    return HttpResponse.json(mockFleet);
  }),

  // GET /api/trains/:id
  http.get('/api/trains/:id', async ({ params }) => {
    await delay(100);
    const train = mockFleet.find(t => t.id === params.id);
    if (!train) return new HttpResponse(null, { status: 404 });
    return HttpResponse.json(train);
  }),

  // Error scenario handlers
  http.get('/api/trains/error', () => {
    return new HttpResponse(null, { status: 500 });
  }),
];
```

