### 7.2 Visual Test Example

```typescript
// tests/visual/kpi-card.visual.spec.ts
import { test, expect } from '@playwright/test';

const STORIES = [
  'design-system-molecules-kpicard--fleet-availability',
  'design-system-molecules-kpicard--pm-compliance',
  'design-system-molecules-kpicard--resource-utilisation',
  'design-system-molecules-kpicard--cost-variance',
  'design-system-molecules-kpicard--warning',
  'design-system-molecules-kpicard--critical',
];

test.describe('KPICard Visual Regression', () => {
  for (const storyId of STORIES) {
    test(`${storyId} matches screenshot`, async ({ page }) => {
      await page.goto(`/iframe.html?id=${storyId}&viewMode=story`);
      await page.waitForLoadState('networkidle');

      // Wait for any animations to complete
      await page.waitForTimeout(500);

      await expect(page).toHaveScreenshot(`${storyId}.png`);
    });
  }
});
```

