// Every component should have an Accessibility story
export const AccessibilityAudit: Story = {
  play: async ({ canvasElement }) => {
    const canvas = within(canvasElement);

    // Verify keyboard navigation
    await userEvent.tab();
    expect(canvas.getByRole('button')).toHaveFocus();

    // Verify ARIA labels
    expect(canvas.getByRole('progressbar')).toHaveAttribute('aria-valuemin', '0');
